#include "../cabeceras/Incidencia.h"
#include "../cabeceras/excepciones/ErrorRango.h"

int Incidencia::contador = 0;

Incidencia::Incidencia(Equipo* e, int severidad, int dia):equipo(e),dia(dia)
{
    if (severidad>3 || severidad<1) throw ErrorRango("La severidad debe de estar entre 1 y 3");
    this->severidad = severidad;
    id = to_string(contador);
    contador++;
};

int Incidencia::getSeveridad() const { return severidad; }

string Incidencia::toString() const {
    stringstream s;
    string nivelSeveridad;
    switch(severidad) {
        case BAJA:
            nivelSeveridad = "Baja";
            break;
        case MEDIA:
            nivelSeveridad = "Media";
            break;
        case ALTA:
            nivelSeveridad = "Alta";
            break;
        default:
            nivelSeveridad = "Desconocida";
    }

    s << "ID: " << id << " | Severidad: " << nivelSeveridad << " | Dia: " << dia;
    if (equipo != nullptr) {
        s << " | Equipo: " << equipo->getId();
    }
    return s.str();
}

