    switch(severidad) {
        case BAJA:
            nivelSeveridad = "Baja";
            break;
        case MEDIA:
            nivelSeveridad = "Media";
            break;
        case ALTA:
            nivelSeveridad = "Alta";
            break;
        default:
            nivelSeveridad = "Desconocida";
    }

    s << "ID: " << id << " | Severidad: " << nivelSeveridad << " | Dia: " << dia;
    if (equipo != nullptr) {
        s << " | Equipo: " << equipo->getId();
    }
    return s.str();
}

