#ifndef PROYECTO_1_INCIDENCIA_H
#define PROYECTO_1_INCIDENCIA_H

#include "equipos/Equipo.h"
#include <sstream>
using namespace std;
class Equipo;

enum Severidad {
    BAJA = 0,
    MEDIA = 1,
    ALTA = 2
};

class Incidencia {
private:
    static int contador;
    string id;
    Equipo* equipo; //Equipo que presenta esta incidencia
